+      {
+        res.success = true;
+        res.status_message = "DeleteLight: " + req.light_name + " successfully deleted";
+        return true;
+      }
+      // Check every 100ms
+      usleep(100000);
+    }
+  }
+
+  res.status_message = "DeleteLight: Timeout reached while removing light \"" + req.light_name
+                       + "\"";
+
